javascript代码：
```javascript
<script>
    //回车调用
    function calAge(e) {
        var evt = window.event || e;
        if (evt.keyCode == 13) {
            // 调用搜索函数
            entersearch();
        }
    }
    //end
    function entersearch() {
        var inpCont = $("#wd").val();
        if (inpCont.replace(/(^\s*)|(\s*$)/g, "") == "") { //----判断是否为空或者空格---
            alert("搜索不能为空！");
            return; //------如果为空，阻止函数继续往下执行----          
        } else {
            //加载新的链接
            window.open("链接" + $('#wd').val());
        };
    }
</script>
